/**
 * @param {number[]} nums
 * @return {number}
 */
function solve(nums) {
    const n = nums.length;

    if (n < 3) {
        return 0;
    }

    // N' is the number of potential peak indices (1 to n-2)
    const N_prime = n - 2;
    // K_max is the maximum possible number of special indices
    const K_max = Math.ceil(N_prime / 2);

    // Step 1: Calculate the minimum cost W[i] to make index i a peak, 
    // assuming neighbors are at their original values.
    // W is 1-indexed conceptually, stored in an array of size N_prime + 1.
    const W = new Array(N_prime + 1);
    const INF = Number.MAX_SAFE_INTEGER;

    for (let i = 1; i <= N_prime; i++) {
        const val = nums[i];
        const leftNeighbor = nums[i - 1];
        const rightNeighbor = nums[i + 1];

        // Cost to make val > leftNeighbor: max(0, leftNeighbor + 1 - val)
        const costLeft = Math.max(0, leftNeighbor + 1 - val);
        // Cost to make val > rightNeighbor: max(0, rightNeighbor + 1 - val)
        const costRight = Math.max(0, rightNeighbor + 1 - val);

        W[i] = Math.max(costLeft, costRight);
    }

    // Step 2: Dynamic Programming
    // DP[k] stores the minimum cost to select exactly k non-adjacent peaks 
    // up to the current processed index i.

    // D2 corresponds to DP[i-2]
    // D1 corresponds to DP[i-1]
    // D corresponds to DP[i]

    // Initialize D2 (i=0 state)
    // Size K_max + 1, indexed 0 to K_max
    let D2 = new Array(K_max + 1).fill(INF);
    D2[0] = 0;

    // Initialize D1 (i=-1 state, conceptually empty before i=1)
    let D1 = new Array(K_max + 1).fill(INF);
    D1[0] = 0;

    // Iterate through potential peak indices i = 1 to N_prime
    for (let i = 1; i <= N_prime; i++) {
        let D = new Array(K_max + 1).fill(INF);
        D[0] = 0; // Cost to select 0 peaks is always 0

        const Wi = W[i];

        for (let k = 1; k <= K_max; k++) {

            // Option 1: Skip index i. Minimum cost is inherited from D1 (i-1).
            D[k] = D1[k];

            // Option 2: Select index i. Requires k-1 peaks from i-2 (D2).
            if (D2[k - 1] !== INF) {
                const costIfSelected = D2[k - 1] + Wi;
                D[k] = Math.min(D[k], costIfSelected);
            }
        }

        // Update states for the next iteration
        D2 = D1;
        D1 = D;
    }

    // The result is the minimum cost to achieve K_max peaks using indices up to N_prime.
    const result = D1[K_max];

    // Since K_max is achievable, result should not be INF.
    return result;
}

